hooks.command:
root="${PLUGIN_ROOT:-${CLAUDE_PLUGIN_ROOT:-${CODEX_PLUGIN_ROOT:-}}}"; host=claude; if [ -n "${PLUGIN_ROOT:-}" ] || [ -n "${CODEX_PLUGIN_ROOT:-}" ]; then host=codex; fi; if [ -n "$root" ] && [ -f "$root/scripts/ambient.py" ]; then output="$(env -i PATH="${PATH:-}" HOME="${HOME:-}" USERPROFILE="${USERPROFILE:-}" APPDATA="${APPDATA:-}" TMPDIR="${TMPDIR:-}" TMP="${TMP:-}" TEMP="${TEMP:-}" LANG="${LANG:-}" LC_ALL="${LC_ALL:-}" LC_CTYPE="${LC_CTYPE:-}" XDG_DATA_HOME="${XDG_DATA_HOME:-}" PYTHONUTF8=1 python3 "$root/scripts/ambient.py" --hook --host "$host" 2>/dev/null)" && printf '%s
' "$output" || printf '{}
'; else printf '{}
'; fi
